const fs = require("fs");
const path = require("path");

const PATCH_NAME = "BARNDAKSA_LOGO_AND_BROWSER_ICON_PATCH";
const PATCH_PAYLOAD = [{"path": "app/layout.tsx", "encoding": "base64", "content": ""}, {"path": "app/c/[slug]/layout.tsx", "encoding": "base64", "content": ""}, {"path": "components/cafe/cafe-logo.tsx", "encoding": "base64", "content": ""}, {"path": "public/brand/barndaksa-logo-brown.png", "encoding": "base64", "content": ""}, {"path": "public/brand/barndaksa-logo-dark.png", "encoding": "base64", "content": ""}, {"path": "public/brand/barndaksa-logo-brown-bg.png", "encoding": "base64", "content": ""}, {"path": "public/brand/branda-logo-brown.png", "encoding": "base64", "content": ""}, {"path": "public/brand/branda-logo-dark.png", "encoding": "base64", "content": ""}, {"path": "public/brand/branda-logo-brown-bg.png", "encoding": "base64", "content": ""}, {"path": "public/brand/barndaksa-app-icon-512.png", "encoding": "base64", "content": ""}, {"path": "public/brand/barndaksa-app-icon-192.png", "encoding": "base64", "content": ""}, {"path": "public/brand/barndaksa-maskable-icon-512.png", "encoding": "base64", "content": ""}, {"path": "public/apple-touch-icon.png", "encoding": "base64", "content": ""}, {"path": "public/favicon.ico", "encoding": "base64", "content": ""}, {"path": "app/icon.png", "encoding": "base64", "content": ""}, {"path": "app/apple-icon.png", "encoding": "base64", "content": ""}, {"path": "app/favicon.ico", "encoding": "base64", "content": ""}];

function fail(message) {
  console.error(`\n[${PATCH_NAME}] ${message}\n`);
  process.exit(1);
}

function findProjectRoot() {
  const candidates = [process.cwd(), path.dirname(__dirname), path.resolve(__dirname, "..")];
  for (const candidate of candidates) {
    if (candidate && fs.existsSync(path.join(candidate, "package.json"))) return candidate;
  }
  fail("ضع مجلد الباتش داخل جذر المشروع ثم شغل: node BARNDAKSA_LOGO_AND_BROWSER_ICON_PATCH/apply-patch.cjs");
}

function removeDirIfExists(target) {
  try {
    if (fs.existsSync(target) && fs.statSync(target).isDirectory()) {
      fs.rmSync(target, { recursive: true, force: true });
      console.log(`✓ Removed stale folder: ${path.relative(process.cwd(), target) || target}`);
    }
  } catch (error) {
    console.warn(`! Could not remove stale folder ${target}: ${error.message}`);
  }
}

function writeFileSafe(projectRoot, relativePath, contentBuffer, backupRoot) {
  const cleanPath = relativePath.replaceAll("\\", "/");
  if (cleanPath.includes("..") || path.isAbsolute(cleanPath)) fail(`Unsafe patch path blocked: ${relativePath}`);

  const target = path.join(projectRoot, cleanPath);
  const backup = path.join(backupRoot, cleanPath);
  fs.mkdirSync(path.dirname(target), { recursive: true });

  if (fs.existsSync(target)) {
    fs.mkdirSync(path.dirname(backup), { recursive: true });
    fs.copyFileSync(target, backup);
  }

  fs.writeFileSync(target, contentBuffer);
  console.log(`✓ ${cleanPath}`);
}

function patchTextFile(projectRoot, relativePath, updater, backupRoot) {
  const cleanPath = relativePath.replaceAll("\\", "/");
  const target = path.join(projectRoot, cleanPath);
  const backup = path.join(backupRoot, cleanPath);
  if (!fs.existsSync(target)) {
    console.warn(`! Skipped missing file: ${cleanPath}`);
    return;
  }

  const before = fs.readFileSync(target, "utf8");
  const after = updater(before);
  if (after === before) {
    console.log(`• No text change needed: ${cleanPath}`);
    return;
  }

  fs.mkdirSync(path.dirname(backup), { recursive: true });
  fs.copyFileSync(target, backup);
  fs.writeFileSync(target, after, "utf8");
  console.log(`✓ Patched ${cleanPath}`);
}

const projectRoot = findProjectRoot();
const stamp = new Date().toISOString().replace(/[:.]/g, "-");
const backupRoot = path.join(projectRoot, ".barndaksa-patch-backups", `${PATCH_NAME}-${stamp}`);

console.log(`\nApplying ${PATCH_NAME}...`);
console.log(`Project root: ${projectRoot}`);
console.log(`Backup root: ${backupRoot}\n`);

for (const file of PATCH_PAYLOAD) {
  if (!file.path || file.encoding !== "base64" || typeof file.content !== "string") {
    fail(`Invalid embedded patch payload for ${file.path || "unknown file"}`);
  }
  writeFileSafe(projectRoot, file.path, Buffer.from(file.content, "base64"), backupRoot);
}

patchTextFile(
  projectRoot,
  "app/api/pwa/[slug]/manifest/route.ts",
  (content) => {
    let next = content.replace(
      /const\s+DEFAULT_BARNDAKSA_ICON\s*=\s*["'][^"']+["'];/,
      'const DEFAULT_BARNDAKSA_ICON = "/brand/barndaksa-app-icon-512.png";'
    );

    next = next.replace(
      /purpose:\s*["']any maskable["']/g,
      'purpose: "any"'
    );

    if (!next.includes("/brand/barndaksa-maskable-icon-512.png")) {
      next = next.replace(
        /icons:\s*\[([\s\S]*?)\n\s*\],/,
        (match, body) => `icons: [${body}\n      {\n        src: "/brand/barndaksa-maskable-icon-512.png",\n        sizes: "512x512",\n        type: "image/png",\n        purpose: "maskable",\n      },\n    ],`
      );
    }

    return next;
  },
  backupRoot
);

patchTextFile(
  projectRoot,
  "components/cafe/cafe-page-client.tsx",
  (content) => content.replace(
    "const logoUrl = settings.logoAssetId;",
    "const logoUrl = settings.logoDataUrl ?? settings.logoAssetId;"
  ),
  backupRoot
);

console.log("\nCleaning old extracted patch payload folders so TypeScript does not scan them...");
removeDirIfExists(path.join(__dirname, "patch-files"));
removeDirIfExists(path.join(__dirname, "files"));
removeDirIfExists(path.join(projectRoot, "patch-files"));

console.log("\nDone. Next commands:");
console.log("npm exec tsc -- --noEmit");
console.log("npm run build");
console.log("\nWhat this changes:");
console.log("- Replaces Barndaksa/Branda logo assets with the new uploaded logo.");
console.log("- Adds favicon, Apple icon, and PWA icons so the browser does not show the Vercel/default icon.");
console.log("- Adds branch-level browser metadata: brand logo if available, otherwise Barndaksa logo.");
console.log("- Makes CafeLogo fall back to the Barndaksa logo when a brand logo is missing.");
console.log("- No database migration required.");
